#!/usr/bin/env python3\nimport paramiko\nimport time\n\nHOST = "168.119.79.238"\nPORT = 77\nUSERNAME = "sanliur"\nPASSWORD = "CHANGE_ME_CWP_SSH_PASSWORD"\n\ndef main():\n    ssh = paramiko.SSHClient()\n    ssh.set_missing_host_key_policy(paramiko.AutoAddPolicy())\n    ssh.connect(HOST, port=PORT, username=USERNAME, password=PASSWORD, \n                timeout=20, look_for_keys=False, allow_agent=False)\n    \n    channel = ssh.invoke_shell()\n    time.sleep(2)\n    \n    print("Fixing database connection...")\n    \n    # Create .pgpass\n    pgpass = "localhost:5432:sanliur_sanliurfa:sanliur_sanliurfa:CHANGE_ME_DB_PASSWORD"\n    channel.send(f"echo '{pgpass}' > ~/.pgpass\n")\n    time.sleep(1)\n    channel.send("chmod 600 ~/.pgpass\n")\n    time.sleep(1)\n    \n    # Fix env\n    channel.send("cd /home/sanliur/public_html\n")\n    time.sleep(1)\n    \n    # Create new env\n    env = """SITE_URL=https://sanliurfa.com\nNODE_ENV=production\nPORT=6000\nHOST=127.0.0.1\nDATABASE_URL=postgresql://sanliur_sanliurfa@localhost:5432/sanliur_sanliurfa\nJWT_SECRET=change-this-secret-key-32chars-long\n"""\n    \n    channel.send(f"cat > .env.production << 'EOF'\n{env}EOF\n")\n    time.sleep(2)\n    \n    # Restart\n    channel.send("source ~/.nvm/nvm.sh && pm2 restart sanliurfa\n")\n    time.sleep(5)\n    \n    # Test\n    channel.send("curl -s http://127.0.0.1:4321/api/health 2>&1\n")\n    time.sleep(3)\n    \n    output = ""\n    while channel.recv_ready():\n        output += channel.recv(4096).decode('utf-8', errors='ignore')\n        time.sleep(1)\n    \n    print("OUTPUT:")\n    print(output[-400:])\n    \n    channel.close()\n    ssh.close()\n\nif __name__ == "__main__":\n    main()\n
